// -----------------------------------------------------------------------// UPilot Editor — M26 editor.delay (main-thread wall-clock delay for E2E)// SPDX-License-Identifier: MIT// -----------------------------------------------------------------------using System.Threading;using System.Threading.Tasks;using UnityEditor;using UnityEngine;namespace CodingRiver.UPilot{    public sealed class UPilotEditorDelayService    {        private readonly UPilotBridge _bridge;        public UPilotEditorDelayService(UPilotBridge bridge)        {            _bridge = bridge;            Logger.Log("[EditorDelay] EditorDelayService 初始化");        }        public void RegisterCommands()        {            _bridge.Router.Register("editor.delay", HandleEditorDelayAsync);        }        private async Task HandleEditorDelayAsync(string id, string json, CancellationToken token)        {            Logger.Log("EditorDelay", $"开始延迟 id={id}");            var command = JsonUtility.FromJson<EditorDelayMessage>(json);            var delayMs = command?.payload?.delayMs ?? 0;            if (delayMs < 0) delayMs = 0;            if (delayMs > 300000) delayMs = 300000;            var tcs = new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);            double start = 0d;            void Tick()            {                if ((EditorApplication.timeSinceStartup - start) * 1000.0 >= delayMs)                {                    EditorApplication.update -= Tick;                    tcs.TrySetResult(true);                }            }            _bridge.EnqueueTracked(id, () =>            {                start = EditorApplication.timeSinceStartup;                if (delayMs <= 0)                {                    tcs.TrySetResult(true);                    return;                }                EditorApplication.update += Tick;                Tick();            });            await tcs.Task;            await _bridge.SendResultAsync(                id,                "editor.delay",                new GenericOkPayload { ok = true, state = $"delayed_{delayMs}ms" },                token);        }    }}